import subprocess

def generate_requirements_txt():
    """Generates a requirements.txt file with hashes."""
    subprocess.run(["pip", "freeze", "--all", "--exists", ">", "requirements.txt"])

def update_requirements_txt(dependencies):
    """Updates a requirements.txt file with new dependencies."""
    with open("requirements.txt", "a") as f:
        for dependency in dependencies:
            f.write(f"{dependency}\n")

def generate_poetry_lock():
    """Generates a Poetry lock file."""
    subprocess.run(["poetry", "lock"])

def update_poetry_lock(dependencies):
    """Updates a Poetry lock file with new dependencies."""
    with open("poetry.lock", "a") as f:
        for dependency in dependencies:
            f.write(f"[dependency]\nname = {dependency}\n")

def ensure_consistent_versions():
    """Ensures consistent dependency versions across development and production."""
    # Generate requirements.txt with hashes
    generate_requirements_txt()

    # Create a copy of requirements.txt for production
    subprocess.run(["cp", "requirements.txt", "production_requirements.txt"])

    # Ensure production requirements are consistent
    subprocess.run(["pip", "install", "-r", "production_requirements.txt"])

# Example usage:
dependencies = ["numpy", "pandas"]

# Update requirements.txt with new dependencies
update_requirements_txt(dependencies)

# Update Poetry lock file with new dependencies
update_poetry_lock(dependencies)

# Ensure consistent dependency versions across development and production
ensure_consistent_versions()